UPDATE checkup_contract_sub_type
SET checkup_contract_type_id = #{checkupContractTypeId}
  , sub_type_name            = #{subTypeName}
  , select_a_count           = #{selectACount}
  , select_a_memo            = #{selectAMemo}
  , select_b_count           = #{selectBCount}
  , select_b_memo            = #{selectBMemo}
  , select_c_count           = #{selectCCount}
  , select_c_memo            = #{selectCMemo}
  , select_d_count           = #{selectDCount}
  , select_d_memo            = #{selectDMemo}
  , select_e_count           = #{selectECount}
  , select_e_memo            = #{selectEMemo}
  , select_f_count           = #{selectFCount}
  , select_f_memo            = #{selectFMemo}
  , updated_at               = NOW()
  , updated_user_id          = #{sessionUserId}
WHERE checkup_contract_sub_type_id = #{checkupContractSubTypeId}

UPDATE item_class
SET item_class_code = #{code}
  , item_class_name = #{name}
  , updated_at      = NOW()
  , updated_user_id = #{sessionUserId}
WHERE item_class_id = #{id}

UPDATE item_category
SET item_category_code = #{code}
  , item_category_name = #{name}
  , updated_at         = NOW()
  , updated_user_id    = #{sessionUserId}
WHERE item_category_id = #{id}

UPDATE item
SET item_code       = #{code}
  , item_name       = #{name}
  , item_desc       = #{itemDesc}
  , updated_at      = NOW()
  , updated_user_id = #{sessionUserId}
WHERE item_id = #{id}

UPDATE item_class
SET deleted_at      = NOW()
  , deleted_user_id = #{sessionUserId}
WHERE item_class_id = #{id}

